code.C:
#include <stdio.h>

long long factorial(int n){
    if(n<=1) return 1LL;
    return n*factorial(n-1);
}

int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N;
        scanf("%d",&N);
        printf("%lld\n",factorial(N));
    }
    return 0;
}

